var DEFAULT_OUTPUT_FILE = "index.html";
function resolveOutFile(input) {
  const outFile = getOptionString(
    input.options,
    "outFile",
    DEFAULT_OUTPUT_FILE
  );
  const trimmedOutFile = outFile.trim();
  const finalOutFile = trimmedOutFile.length > 0 ? trimmedOutFile : DEFAULT_OUTPUT_FILE;
  assert(
    finalOutFile.endsWith(".html"),
    `Invalid outFile "${finalOutFile}". The output file must end with .html`
  );
  return finalOutFile;
}
__name(resolveOutFile, "resolveOutFile");
function removePositionReplacer(key, value) {
  return key === "position" ? void 0 : value;
}
__name(removePositionReplacer, "removePositionReplacer");
var generate = definePlugin((input) => {
  const outFile = resolveOutFile(input);
  const ir = escapeScriptTag(JSON.stringify(input.ir, removePositionReplacer));
  const html = build_default.replace(
    "window.__vdl_ir = {};",
    `window.__vdl_ir = ${ir};`
  );
  return {
    files: [
      {
        path: outFile,
        content: html
      }
    ]
  };
});
